func  (this *BlockchaincomCore) ParseTransaction(transaction any, optionalArgs ...any) any  {
    //
    // deposit
    //
    //     {
    //         "depositId":"748e9180-be0d-4a80-e175-0156150efc95",
    //         "amount":0.009,
    //         "currency":"ETH",
    //         "address":"0xEC6B5929D454C8D9546d4221ace969E1810Fa92c",
    //         "state":"COMPLETED",
    //         "txHash":"582114562140e51a80b481c2dfebaf62b4ab9769b8ff54820bb67e34d4a3ab0c",
    //         "timestamp":1633697196241
    //     }
    //
    // withdrawal
    //
    //     {
    //         "amount":30.0,
    //         "currency":"USDT",
    //         "beneficiary":"cab00d11-6e7f-46b7-b453-2e8ef6f101fa", // blockchain specific id
    //         "withdrawalId":"99df5ef7-eab6-4033-be49-312930fbd1ea",
    //         "fee":34.005078,
    //         "state":"COMPLETED",
    //         "timestamp":1634218452549
    //     }
    //
    currency := GetArg(optionalArgs, 0, nil)
    _ = currency
    var typeVar any = nil
    var id any = nil
    var amount any = this.SafeNumber(transaction, "amount")
    var timestamp any = this.SafeInteger(transaction, "timestamp")
    var currencyId any = this.SafeString(transaction, "currency")
    var code any = this.SafeCurrencyCode(currencyId, currency)
    var state any = this.SafeString(transaction, "state")
    if IsTrue(InOp(transaction, "depositId")) {
        typeVar = "deposit"
        id = this.SafeString(transaction, "depositId")
    } else if IsTrue(InOp(transaction, "withdrawalId")) {
        typeVar = "withdrawal"
        id = this.SafeString(transaction, "withdrawalId")
    }
    var feeCost any = Ternary(IsTrue((IsEqual(typeVar, "withdrawal"))), this.SafeNumber(transaction, "fee"), nil)
    var fee any = nil
    if IsTrue(!IsEqual(feeCost, nil)) {
        fee = map[string]any {
            "currency": code,
            "cost": feeCost,
        }
    }
    var address any = this.SafeString(transaction, "address")
    var txid any = this.SafeString(transaction, "txhash")
    return map[string]any {
        "info": transaction,
        "id": id,
        "txid": txid,
        "timestamp": timestamp,
        "datetime": this.Iso8601(timestamp),
        "network": nil,
        "addressFrom": nil,
        "address": address,
        "addressTo": address,
        "tagFrom": nil,
        "tag": nil,
        "tagTo": nil,
        "type": typeVar,
        "amount": amount,
        "currency": code,
        "status": this.ParseTransactionState(state),
        "updated": nil,
        "comment": nil,
        "internal": nil,
        "fee": fee,
    }
}
